### วิธีตรวจสอบข้อมูลในรูปแบบอื่น ๆ  

หากข้อมูลถูกห่อไว้ในโครงสร้างต่อไปนี้  

```json
{
  "content": [
    {
      "type": "text",
      "text": "{ \"rows\": [ { ... } ] }"
    }
  ]
}
```

1. ดึงค่า `content[0].text`  
2. แปลงสตริงภายใน `text` เป็น JSON (เช่น `JSON.parse(text)`)  
3. ตรวจสอบอาร์เรย์ `rows` ภายในนั้นว่า มีรายการใดที่ `status` เท่ากับ `"ACTIVE"` หรือไม่  
4. หากพบให้คืนค่า `loan_id` ของรายการนั้น; หากไม่พบให้คืน `null`

**ตัวอย่างโค้ด (JavaScript)**  

```javascript
function getActiveLoanId(data) {
  // 1️⃣ ตรวจสอบว่าข้อมูลอยู่ในรูปแบบปกติหรือแบบ content.text
  let rows;
  if (Array.isArray(data)) {
    rows = data;
  } else if (data.content && data.content[0] && data.content[0].type === 'text') {
    const jsonString = data.content[0].text;
    const parsed = JSON.parse(jsonString);   // { rows: [ ... ] }
    rows = parsed.rows;
  } else {
    return null; // รูปแบบข้อมูลไม่รองรับ
  }

  // 2️⃣ หา loan_id ที่ status = "ACTIVE"
  const active = rows.find(row => row.status === 'ACTIVE');
  return active ? active.loan_id : null;
}

// ตัวอย่างการเรียกใช้
const resultSet = [
  {
    "loan_id":4,
    "contract_number":"LO20250208-0004",
    "status":"ACTIVE",
    // ...อื่น ๆ
  }
];
console.log(getActiveLoanId(resultSet)); // 4
```

---

สรุป: จากผลลัพธ์ที่ให้มา `loan_id` ที่มีสถานะ **ACTIVE** คือ **4**; ถ้าไม่มีสัญญาใดที่อยู่ในสถานะ ACTIVE ให้ส่ง `null` แทน.

